INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "キャル", 0.0, 7001, 0, 7, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "コッコロ", 0.0, 7002, 0, 7, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "ペコリーヌ", 0.0, 7003, 0, 7, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ジュエルを食べ物…\nいえ、貴重品と交換できます！", "ペコリーヌ", 0.0, 10001, 0, 10, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "キャル", 0.0, 10002, 0, 10, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "コッコロ", 0.0, 10003, 0, 10, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "シェフィ", 0.0, 10004, 2104010, 10, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "ペコリーヌ", 0.0, 12001, 0, 12, -416.5, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "キャル", 0.0, 13001, 0, 13, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "コッコロ", 0.0, 13002, 0, 13, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "シェフィ", 0.0, 13003, 2104010, 13, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "ペコリーヌ", 0.0, 13004, 0, 13, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "コッコロ", 0.0, 14001, 0, 14, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "シェフィ", 0.0, 14002, 2104010, 14, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "ペコリーヌ", 0.0, 14003, 0, 14, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "キャル", 0.0, 14004, 0, 14, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "コッコロ", 0.0, 15001, 0, 15, -470.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "シェフィ", 0.0, 16001, 2104010, 16, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "ペコリーヌ", 0.0, 16002, 0, 16, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "キャル", 0.0, 16003, 0, 16, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "コッコロ", 0.0, 16004, 0, 16, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (" こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "コッコロ", 0.0, 17002, 0, 17, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "キャル", 0.0, 17004, 0, 25, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "コッコロ", 0.0, 17005, 0, 25, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "シェフィ", 0.0, 17006, 2104010, 25, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "ペコリーヌ", 0.0, 17007, 0, 25, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "カリン", 0.0, 18001, 0, 18, -363.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "カリン", 0.0, 18002, 0, 18, -363.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 2, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "カリン", 0.0, 19001, 0, 19, -470.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 3, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "カリン", 0.0, 19002, 0, 19, -470.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 4, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "カリン", 0.0, 20001, 0, 20, -470.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 5, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "カリン", 0.0, 20002, 0, 20, -470.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 6, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "キャル", 0.0, 21001, 0, 21, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "コッコロ", 0.0, 21002, 0, 21, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "シェフィ", 0.0, 21003, 2104010, 21, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "ペコリーヌ", 0.0, 21004, 0, 21, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "カリン", 0.0, 22001, 0, 22, -430.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "カリン", 0.0, 22002, 0, 22, -430.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 2, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "カリン", 0.0, 23001, 0, 23, -430.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 3, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "カリン", 0.0, 23002, 0, 23, -430.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 4, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "エリコ（バレンタイン）", 4.08, 24001, 0, 24, -385.0, 1, 109001, 8.0, "2019/01/31 12:00:00", 1, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "エリコ（バレンタイン）", 5.0, 24002, 0, 24, -385.0, 1, 109001, 8.0, "2019/01/31 12:00:00", 2, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "エリコ（バレンタイン）", 10.11, 24003, 0, 24, -385.0, 1, 109001, 8.0, "2019/01/31 12:00:00", 3, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "エリコ（バレンタイン）", 4.0, 24004, 0, 24, -385.0, 1, 109001, 8.0, "2019/01/31 12:00:00", 4, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "エリコ（バレンタイン）", 6.0, 24005, 0, 24, -385.0, 1, 109001, 8.0, "2019/01/31 12:00:00", 5, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "エリコ（バレンタイン）", 0.0, 24006, 0, 24, 0.0, 1, 109002, 0.0, "2019/01/31 12:00:00", 6, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "エリコ（バレンタイン）", 0.0, 24007, 0, 24, 0.0, 1, 109002, 0.0, "2019/01/31 12:00:00", 7, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "エリコ（バレンタイン）", 0.0, 24008, 0, 24, 0.0, 1, 109002, 0.0, "2019/01/31 12:00:00", 8, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "エリコ（バレンタイン）", 0.0, 24009, 0, 24, 0.0, 1, 109002, 0.0, "2019/01/31 12:00:00", 9, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "エリコ（バレンタイン）", 0.0, 24010, 0, 24, 0.0, 1, 109002, 0.0, "2019/01/31 12:00:00", 10, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "シズル（バレンタイン）", 2.12, 24011, 0, 24, -385.0, 1, 109101, 8.0, "2019/01/31 12:00:00", 1, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "シズル（バレンタイン）", 4.19, 24012, 0, 24, -385.0, 5, 109101, 8.0, "2019/01/31 12:00:00", 2, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "シズル（バレンタイン）", 2.3, 24013, 0, 24, -385.0, 2, 109101, 8.0, "2019/01/31 12:00:00", 3, 10011, 4, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "シズル（バレンタイン）", 0.0, 24014, 0, 24, 0.0, 1, 109102, 0.0, "2019/01/31 12:00:00", 4, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "シズル（バレンタイン）", 5.23, 24015, 0, 24, -385.0, 5, 109101, 8.0, "2019/01/31 12:00:00", 5, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "シズル（バレンタイン）", 0.0, 24016, 0, 24, 0.0, 1, 109102, 0.0, "2019/01/31 12:00:00", 6, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "シズル（バレンタイン）", 5.01, 24017, 0, 24, -385.0, 1, 109101, 8.0, "2019/01/31 12:00:00", 7, 10011, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "シズル（バレンタイン）", 0.0, 24018, 0, 24, 0.0, 1, 109102, 0.0, "2019/01/31 12:00:00", 8, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "シズル（バレンタイン）", 0.0, 24019, 0, 24, 0.0, 1, 109102, 0.0, "2019/01/31 12:00:00", 9, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "シズル（バレンタイン）", 0.0, 24020, 0, 24, 0.0, 1, 109102, 0.0, "2019/01/31 12:00:00", 10, 10011, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "シェフィ", 0.0, 26001, 2104010, 26, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "ペコリーヌ", 0.0, 26002, 0, 26, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "キャル", 0.0, 26003, 0, 26, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "コッコロ", 0.0, 26004, 0, 26, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "シェフィ", 0.0, 27001, 2104010, 27, -363.0, 2, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "ペコリーヌ", 0.0, 27002, 0, 27, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "キャル", 0.0, 27003, 0, 27, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "コッコロ", 0.0, 27004, 0, 27, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
