INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 0.0, 33002, 0, 33, -409.0, 1, 190801, 0.0, "2019/12/20 5:00:00", 4, 0, 1, "2020/01/04 4:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", "カリン", 0.0, 34001, 0, 34, -409.0, 1, 190801, 0.0, "2020/01/04 5:00:00", 5, 0, 1, "2020/01/10 11:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "カリン", 0.0, 34002, 0, 34, -409.0, 1, 190801, 0.0, "2020/01/04 5:00:00", 6, 0, 1, "2020/01/10 11:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "ペコリーヌ", 5.3, 38001, 0, 38, -458.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "ペコリーヌ", 6.5, 38002, 0, 38, -458.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 2, 0, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("", "ペコリーヌ", 0.0, 39005, 0, 39, 9999.0, 3, 105801, 9999.0, "2020/04/01", 0, 0, 3, "2020/04/08 23:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "カリン", 0.0, 40001, 0, 40, -430.0, 1, 190801, 0.0, "2015/12/17 15:00:00", 2, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "シェフィ", 0.0, 41001, 2104010, 41, -363.0, 1, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "ペコリーヌ", 0.0, 41002, 0, 41, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "キャル", 0.0, 41003, 0, 41, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "コッコロ", 0.0, 41004, 0, 41, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "コッコロ", 0.0, 42001, 0, 42, -416.5, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "シェフィ", 0.0, 42002, 2104010, 42, -416.5, 1, 106401, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "ペコリーヌ", 0.0, 42003, 0, 42, -416.5, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "キャル", 0.0, 42004, 0, 42, -416.5, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "ペコリーヌ", 0.0, 43001, 0, 43, -363.0, 1, 105801, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "コッコロ", 0.0, 43002, 0, 43, -363.0, 1, 105901, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "キャル", 0.0, 43003, 0, 43, -363.0, 1, 106001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "アメス", 0.0, 43004, 0, 44, -416.5, 1, 123001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "アメス", 0.0, 43005, 0, 44, -416.5, 1, 123001, 0.0, "2015/12/17 15:00:00", 2, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "アメス", 5.79, 43006, 0, 45, -416.5, 1, 123001, 0.0, "2015/12/17 15:00:00", 3, 0, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "アメス", 0.0, 46001, 0, 46, -371.5, 1, 123001, 0.0, "2015/12/17 15:00:00", 1, 0, 1, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "シズル", 0.0, 47001, 0, 47, -416.5, 2, 104901, 0.0, "2015/12/17 15:00:00", 1, 0, 2, "2030/12/17 14:59:59");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES ("ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "リノ", 9.32, 47002, 0, 47, -416.5, 1, 101101, 0.0, "2015/12/17 15:00:00", 1, 0, 2, "2030/12/17 14:59:59");
